class Strategy_SELFISH_48(BaseStrategy):
    """
    Conservative threshold-based strategy for the Collective Risk Dilemma.

    - Defects in round 1.
    - Uses a rolling estimate of opponent cooperation over a small recent window.
    - Cooperates only when the estimated probability of being pivotal makes
      k * P(exactly m-1 opponents cooperate) strictly greater than 1.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.window_size = 4
        self.stability_threshold = 0.18
        self.shrink_base = 0.65

    def __call__(self, history: PlayerHistory) -> Action:
        gd = self.game_description
        n = gd.n_players
        m = gd.m
        k = gd.k
        if history.round_number == 0:
            return Action.D
        opp_counts = history.opponent_cooperators
        rounds_seen = len(opp_counts)
        if rounds_seen < 2:
            return Action.C if int(opp_counts[-1]) == m - 1 else Action.D
        start = max(0, rounds_seen - self.window_size)
        recent_counts = opp_counts[start:rounds_seen]
        n_opponents = max(1, n - 1)
        recent_rates = np.asarray(recent_counts, dtype=float) / float(n_opponents)
        p_hat = float(np.mean(recent_rates)) if recent_rates.size > 0 else 0.0
        if recent_rates.size > 1:
            spread = float(np.max(recent_rates) - np.min(recent_rates))
            if spread > self.stability_threshold:
                lower_end = float(np.min(recent_rates))
                weight = max(0.0, min(1.0, self.shrink_base + 0.5 * spread))
                p_hat = weight * lower_end + (1.0 - weight) * p_hat
        p_hat = max(0.0, min(1.0, p_hat))
        if m - 1 < 0 or m - 1 > n - 1:
            p_exact = 0.0
        else:
            comb = math.comb(n - 1, m - 1)
            p_exact = comb * p_hat ** (m - 1) * (1.0 - p_hat) ** (n - m)
        return Action.C if k * p_exact > 1.0 else Action.D

class Strategy_SELFISH_49(BaseStrategy):
    """
    Defect by default, but cooperate only after at least three consecutive
    prior rounds in which the number of cooperating opponents was exactly
    m - 1.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.target_opponents = game_description.m - 1

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number == 0:
            return Action.D
        streak = 0
        for q in reversed(history.opponent_cooperators):
            if q == self.target_opponents:
                streak += 1
                if streak >= 3:
                    return Action.C
            else:
                break
        return Action.D

class Strategy_SELFISH_50(BaseStrategy):
    """
    Defect initially, then cooperate only after observing sufficient recent
    opponent support at the threshold for one or two consecutive rounds.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.threshold = max(0, game_description.m - 1)

    def __call__(self, history: PlayerHistory) -> Action:
        round_number = history.round_number
        if round_number == 0:
            return Action.D
        opp = history.opponent_cooperators
        if round_number == 1:
            return Action.C if opp[-1] >= self.threshold else Action.D
        if len(opp) < 2:
            return Action.D
        if opp[-1] >= self.threshold and opp[-2] >= self.threshold:
            return Action.C
        return Action.D

