class Strategy_SELFISH_72(BaseStrategy):
    """
    Defect by default, but cooperate when recent opponent cooperation
    suggests the group is exactly at the knife-edge threshold.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.m = game_description.m

    def __call__(self, history: PlayerHistory) -> Action:
        round_number = history.round_number
        if round_number == 0:
            return Action.D
        if round_number == 1:
            return Action.C if int(history.opponent_cooperators[-1]) == self.m - 1 else Action.D
        x1 = int(history.opponent_cooperators[-1])
        x2 = int(history.opponent_cooperators[-2])
        weighted_estimate = (2 * x1 + x2) / 3.0
        estimate = int(math.floor(weighted_estimate + 0.5))
        return Action.C if estimate == self.m - 1 else Action.D

class Strategy_SELFISH_73(BaseStrategy):
    """
    Defect by default, with a narrow conditional cooperation trigger when the
    opponent cooperation count has been persistently just below the threshold.
    Always defects in the first and final rounds.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.n_players = int(getattr(game_description, 'n_players', 0) or 0)
        self.n_rounds = int(getattr(game_description, 'n_rounds', 0) or 0)
        self.m = int(getattr(game_description, 'm', 0) or 0)
        self.k = float(getattr(game_description, 'k', 0.0) or 0.0)
        self.last_round_number = -1
        self.last_h = None
        self.prev_h = None
        self.last_my_action = None

    def __call__(self, history: PlayerHistory) -> Action:
        round_number = int(history.round_number)
        if round_number == 0:
            self.last_round_number = 0
            self.last_h = int(history.opponent_cooperators[-1]) if len(history.opponent_cooperators) > 0 else None
            self.prev_h = None
            self.last_my_action = Action.D
            return Action.D
        if self.n_rounds > 0 and round_number == self.n_rounds - 1:
            self.prev_h = self.last_h
            self.last_h = int(history.opponent_cooperators[-1]) if len(history.opponent_cooperators) > 0 else None
            self.last_round_number = round_number
            self.last_my_action = Action.D
            return Action.D
        h_prev = int(history.opponent_cooperators[-1]) if len(history.opponent_cooperators) > 0 else 0
        my_prev_action = Action.C if len(history.my_actions) > 0 and bool(history.my_actions[-1]) else Action.D
        if round_number < 2:
            self.prev_h = self.last_h
            self.last_h = h_prev
            self.last_round_number = round_number
            self.last_my_action = Action.D
            return Action.D
        h_prev2 = int(history.opponent_cooperators[-2]) if len(history.opponent_cooperators) >= 2 else 0
        threshold_minus_1 = self.m - 1
        threshold_minus_2 = self.m - 2
        threshold_minus_3 = self.m - 3
        action = Action.D
        if h_prev == threshold_minus_2:
            if h_prev2 >= threshold_minus_2 and my_prev_action == Action.D:
                action = Action.C
        else:
            action = Action.D
        if h_prev >= threshold_minus_1 or h_prev <= threshold_minus_3:
            action = Action.D
        self.prev_h = self.last_h
        self.last_h = h_prev
        self.last_round_number = round_number
        self.last_my_action = action
        return action

