class Strategy_SELFISH_75(BaseStrategy):
    """
    Conservative collective-risk strategy:
    - Never cooperates when k <= 2.
    - Otherwise defects by default and only cooperates after two consecutive
      rounds with exactly m-1 cooperating opponents, with a final-round rule
      that remains conservative.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.n_players = game_description.n_players
        self.n_rounds = game_description.n_rounds
        self.m = game_description.m
        self.k = game_description.k

    def __call__(self, history: PlayerHistory) -> Action:
        round_number = history.round_number
        if round_number == 0:
            return Action.D
        if self.k <= 2:
            return Action.D
        opp = history.opponent_cooperators
        if round_number == self.n_rounds - 1:
            if round_number >= 2:
                if opp[-1] == self.m - 1 and opp[-2] >= self.m - 1:
                    return Action.C
            return Action.D
        if round_number >= 2:
            if opp[-1] == self.m - 1 and opp[-2] >= self.m - 1:
                return Action.C
        return Action.D

