class Strategy_SELFISH_86(BaseStrategy):
    """
    Defect by default, cooperating only after at least two consecutive prior
    rounds where the number of cooperating opponents met the threshold-supporting
    margin (>= m - 1).
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.threshold = max(0, game_description.m - 1)

    def __call__(self, history: PlayerHistory) -> Action:
        t = history.round_number
        if t == 0:
            return Action.D
        if t == 1:
            if history.opponent_cooperators[-1] >= self.threshold:
                return Action.C
            return Action.D
        if history.opponent_cooperators[-1] >= self.threshold and history.opponent_cooperators[-2] >= self.threshold:
            return Action.C
        return Action.D

class Strategy_SELFISH_87(BaseStrategy):
    """
    Threshold-seeking strategy for the Collective Risk Dilemma:
    - Defect in the first and final rounds.
    - Cooperate when opponents were just short of the threshold in the previous round,
      or when a near-miss pattern over the last two rounds suggests our cooperation
      may be pivotal.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.n_players = int(getattr(game_description, 'n_players', 0))
        self.n_rounds = int(getattr(game_description, 'n_rounds', 0))
        self.m = int(getattr(game_description, 'm', 0))
        self.k = float(getattr(game_description, 'k', 0.0))

    def __call__(self, history: PlayerHistory) -> Action:
        round_number = int(getattr(history, 'round_number', 0))
        if round_number == 0 or round_number >= self.n_rounds - 1:
            return Action.D
        opponent_cooperators = getattr(history, 'opponent_cooperators', None)
        if opponent_cooperators is None or len(opponent_cooperators) == 0:
            return Action.D
        last_s = int(opponent_cooperators[-1])
        if round_number == 1:
            return Action.C if last_s == self.m - 1 else Action.D
        prev_s = int(opponent_cooperators[-2])
        if last_s == self.m - 1:
            return Action.C
        if last_s == self.m - 2 and prev_s == self.m - 1:
            return Action.C
        return Action.D

class Strategy_SELFISH_88(BaseStrategy):
    """
    Default-defect strategy that only cooperates as a narrow rescue move when
    the prior round was exactly one opponent short of the threshold and recent
    history suggests the group has been consistently close.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.n_rounds = int(getattr(game_description, 'n_rounds', 0))
        self.m = int(getattr(game_description, 'm', 0))

    def __call__(self, history: PlayerHistory) -> Action:
        t = history.round_number
        if t == 0 or t >= self.n_rounds - 1:
            return Action.D
        last_opp = int(history.opponent_cooperators[-1]) if len(history.opponent_cooperators) > 0 else 0
        last_my = bool(history.my_actions[-1]) if len(history.my_actions) > 0 else False
        last_total = last_opp + (1 if last_my else 0)
        previous_round_threshold_met = last_total >= self.m
        if previous_round_threshold_met:
            return Action.D
        if last_opp == self.m - 1:
            if t == 1:
                return Action.C
            prev_prev_opp = int(history.opponent_cooperators[-2]) if len(history.opponent_cooperators) >= 2 else 0
            if prev_prev_opp >= self.m - 1:
                return Action.C
        return Action.D

class Strategy_SELFISH_89(BaseStrategy):
    """
    Collective-risk trigger strategy:
    - Start with defection.
    - Cooperate only at the tipping point (exactly m-1 opponent cooperators),
      with an initial two-round verification and a stricter rule after that.
    - If the observed cooperation level ever moves away from the tipping point,
      defect until the tipping point is observed for two consecutive rounds.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.tipping_point = max(0, game_description.m - 1)
        self.n_rounds = game_description.n_rounds

    def __call__(self, history: PlayerHistory) -> Action:
        round_number = history.round_number
        if round_number == 0:
            return Action.D
        opp = history.opponent_cooperators
        tp = self.tipping_point
        if round_number >= self.n_rounds - 1:
            return Action.C if opp[-1] == tp else Action.D
        if round_number == 1:
            return Action.C if opp[-1] == tp else Action.D
        q_prev = int(opp[-1])
        q_prev2 = int(opp[-2])
        if q_prev != tp or q_prev2 != tp:
            return Action.D
        if round_number >= 3:
            q_prev3 = int(opp[-3])
            if q_prev3 < tp:
                return Action.D
        return Action.C

class Strategy_SELFISH_90(BaseStrategy):
    """
    Defect initially, then cooperate only when the opponents' recent cooperation
    is consistently close to meeting the threshold.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.threshold_minus_one = game_description.m - 1
        self.window_size = 3

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number == 0:
            return Action.D
        x = int(history.opponent_cooperators[-1])
        start = max(0, history.round_number - self.window_size)
        recent_slice = history.opponent_cooperators[start:history.round_number]
        if len(recent_slice) > 0:
            recent_avg = float(np.mean(recent_slice))
        else:
            recent_avg = 0.0
        if x >= self.threshold_minus_one and recent_avg >= self.threshold_minus_one:
            return Action.C
        return Action.D

