class Strategy_SELFISH_93(BaseStrategy):
    """
    Defect by default, cooperating only when the observed cooperation count
    sits exactly on the threshold edge and is stable or improving over the
    last two rounds.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.last_two_opponent_cooperators = None

    def __call__(self, history: PlayerHistory) -> Action:
        m = self.game_description.m
        round_number = history.round_number

        def _safe_int(value):
            try:
                return int(value)
            except Exception:
                return None
        x_prev = None
        x_prev2 = None
        if round_number >= 1 and len(history.opponent_cooperators) >= 1:
            x_prev = _safe_int(history.opponent_cooperators[-1])
        if round_number >= 2 and len(history.opponent_cooperators) >= 2:
            x_prev2 = _safe_int(history.opponent_cooperators[-2])
        if x_prev is not None or x_prev2 is not None:
            self.last_two_opponent_cooperators = (x_prev2, x_prev)
        if round_number == 0:
            return Action.D
        if round_number == 1:
            if x_prev is not None and x_prev == m - 1:
                return Action.C
            return Action.D
        if x_prev is None or x_prev2 is None:
            return Action.D
        if x_prev == m - 1 and x_prev2 >= m - 2 and (x_prev >= x_prev2):
            return Action.C
        return Action.D

class Strategy_SELFISH_94(BaseStrategy):
    """
    Cooperative only when the previous two rounds were stably near the threshold,
    defects whenever others already meet the threshold, and always defects in the
    first and last round. Tracks a short rolling memory with a 2-round cooldown
    after any weak round.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.good = 0
        self.bad = 0
        self.cooldown = 0
        self.last_processed_round = 0

    def __call__(self, history: PlayerHistory) -> Action:
        n_rounds = getattr(self.game_description, 'n_rounds', 0)
        m = getattr(self.game_description, 'm', 0)
        current_round = int(history.round_number)
        if current_round <= 0:
            self.good = 0
            self.bad = 0
            self.cooldown = 0
            self.last_processed_round = 0
            return Action.D
        if self.last_processed_round != current_round:
            self.good = 0
            self.bad = 0
            self.cooldown = 0
            opp = history.opponent_cooperators
            end = min(current_round, len(opp))
            start = 0
            for idx in range(start, end):
                observed = int(opp[idx])
                if observed >= m - 1:
                    self.good += 1
                    self.bad = 0
                else:
                    self.bad += 1
                    self.good = 0
                    self.cooldown = 2
                if self.cooldown > 0:
                    self.cooldown -= 1
            self.last_processed_round = current_round
        if current_round >= max(0, n_rounds - 1):
            return Action.D
        last_opp = int(history.opponent_cooperators[-1]) if len(history.opponent_cooperators) > 0 else 0
        if self.cooldown > 0:
            return Action.D
        if last_opp >= m:
            return Action.D
        if current_round >= 2:
            prev2 = int(history.opponent_cooperators[-2])
            if last_opp >= m - 1 and prev2 >= m - 1:
                return Action.C
        return Action.D

class Strategy_SELFISH_95(BaseStrategy):
    """
    Tactical threshold-triggered cooperator:
    - Defect on the first round.
    - Cooperate only when the most recent opponent cooperation count is exactly m-1,
      the recent frequency of that state is high enough, and the observed trend is non-decreasing
      when enough history exists.
    - Otherwise defect.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.m = game_description.m
        self.k = game_description.k
        self.threshold = self.m - 1
        self.inv_k = 1.0 / self.k if self.k != 0 else float('inf')

    def __call__(self, history: PlayerHistory) -> Action:
        t = history.round_number
        if t == 0:
            return Action.D
        opp = history.opponent_cooperators
        if len(opp) == 0:
            return Action.D
        last_count = int(opp[-1])
        W = min(5, t - 1)
        if W <= 0:
            return Action.D
        recent = opp[-W:]
        matches = 0
        for x in recent:
            if int(x) == self.threshold:
                matches += 1
        p = matches / W
        if t >= 2 and len(opp) >= 2:
            trend = int(opp[-1]) >= int(opp[-2])
        else:
            trend = True
        if last_count == self.threshold and p > self.inv_k and trend:
            return Action.C
        return Action.D

class Strategy_SELFISH_96(BaseStrategy):
    """
    One-shot rescue strategy:
    - Defect in round 1 and in the final round.
    - In intermediate rounds, cooperate only if the previous round had exactly
      m - 1 total cooperators and this player defected in that previous round.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory) -> Action:
        gd = self.game_description
        round_number = history.round_number
        if round_number == 0:
            return Action.D
        if round_number == gd.n_rounds - 1:
            return Action.D
        prev_my_action = bool(history.my_actions[-1])
        prev_total_cooperators = int(history.opponent_cooperators[-1]) + (1 if prev_my_action else 0)
        if prev_total_cooperators == gd.m - 1 and (not prev_my_action):
            return Action.C
        return Action.D

