class Strategy_SELFISH_106(BaseStrategy):
    """
    Defect by default; cooperate only when the last up to three observed rounds
    show the opponents at exactly m-1 cooperators in at least two of them.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self._m_minus_1 = max(0, game_description.m - 1)

    def __call__(self, history: PlayerHistory) -> Action:
        t = history.round_number
        r = self.game_description.n_rounds
        if t == 0 or t == r - 1:
            return Action.D
        recent = history.opponent_cooperators[max(0, t - 3):t]
        q = 0
        for opp_coops in recent:
            if int(opp_coops) == self._m_minus_1:
                q += 1
        return Action.C if q >= 2 else Action.D

class Strategy_SELFISH_107(BaseStrategy):
    """
    Conservative threshold-support strategy:
    - Start by defecting.
    - Cooperate only in tightly clustered histories where cooperation appears pivotal
      (i.e., the previous round had exactly m-1 cooperating opponents and recent rounds
      repeatedly hovered near that threshold).
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.n_players = game_description.n_players
        self.n_rounds = game_description.n_rounds
        self.m = game_description.m
        self.k = game_description.k

    def __call__(self, history: PlayerHistory) -> Action:
        t = history.round_number + 1
        if history.round_number == 0:
            return Action.D
        x_last = int(history.opponent_cooperators[-1])
        threshold = self.m - 1
        if t <= 3:
            return Action.C if x_last == threshold else Action.D
        L = min(5, history.round_number)
        recent = history.opponent_cooperators[-L:]
        if len(recent) == 0:
            return Action.D
        avg = float(np.mean(recent))
        near = int(np.sum(recent >= threshold))
        exact = int(np.sum(recent == threshold))
        if avg < threshold:
            return Action.D
        if avg > threshold and x_last >= self.m:
            return Action.D
        if x_last == threshold and near >= math.ceil(len(recent) / 2) and (exact >= 2):
            return Action.C
        return Action.D

class Strategy_SELFISH_108(BaseStrategy):
    """
    Always defect strategy for the Collective Risk Dilemma.
    Ignores history and returns D in every round.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self._default_action = Action.D

    def __call__(self, history: PlayerHistory) -> Action:
        if history is None:
            return self._default_action
        round_number = getattr(history, 'round_number', 0)
        if not isinstance(round_number, int) or round_number < 0:
            return self._default_action
        return self._default_action

class Strategy_SELFISH_109(BaseStrategy):
    """
    Defect by default; cooperate only when recent opponent cooperation is
    stable, near the threshold, and the round is not the first or last.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.n_rounds = int(game_description.n_rounds)
        self.m = int(game_description.m)
        self.threshold = max(0, self.m - 1)

    def __call__(self, history: PlayerHistory) -> Action:
        round_number = int(history.round_number)
        if round_number == 0:
            return Action.D
        if round_number >= self.n_rounds - 1:
            return Action.D
        opp = history.opponent_cooperators
        if len(opp) == 0:
            return Action.D
        s_t = int(opp[-1])
        recent_len = 3 if len(opp) >= 3 else len(opp)
        recent = opp[-recent_len:]
        w_t = float(np.mean(recent)) if recent_len > 0 else 0.0
        if len(opp) >= 2:
            u_t = 1 if int(opp[-1]) >= int(opp[-2]) else 0
        else:
            u_t = 0
        if s_t >= self.threshold and w_t >= self.threshold and (u_t == 1):
            return Action.C
        return Action.D

class Strategy_SELFISH_110(BaseStrategy):
    """
    Defect by default, cooperate only as a one-round rescue when the previous
    round was exactly one cooperator short of the threshold and that near-threshold
    pattern appears stable.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.n_players = game_description.n_players
        self.n_rounds = game_description.n_rounds
        self.m = game_description.m
        self.k = game_description.k
        self.threshold_minus_one = max(0, self.m - 1)

    def __call__(self, history: PlayerHistory) -> Action:
        t = history.round_number
        if t == 0:
            return Action.D
        if t == self.n_rounds - 1:
            return Action.D
        s = int(history.opponent_cooperators[-1]) if len(history.opponent_cooperators) > 0 else 0
        if len(history.my_actions) > 0 and bool(history.my_actions[-1]):
            return Action.D
        if s != self.threshold_minus_one:
            return Action.D
        if t == 1:
            return Action.C
        if len(history.opponent_cooperators) >= 2:
            prev_s = int(history.opponent_cooperators[-2])
            if prev_s >= self.threshold_minus_one:
                return Action.C
        return Action.D

