class Strategy_INDIVIDUALISTIC_123(BaseStrategy):
    """
    Risk-averse conditional cooperator for the Collective Risk Dilemma.

    Core behavior:
    - Defect in round 1.
    - Defect in the last two rounds.
    - Defect whenever opponents already meet the threshold without help.
    - After a failure, stay in recovery/defection mode until opponents are just one below
      the threshold, then allow at most a single pivotal cooperation test.
    - If the threshold has held for two consecutive observed rounds, lock into defection
      unless a later failure resets the lock.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self._consecutive_successes = 0
        self._permanent_defect = False
        self._last_processed_round = -1

    def __call__(self, history: PlayerHistory) -> Action:
        gd = self.game_description
        round_number = history.round_number
        m = gd.m
        n_rounds = gd.n_rounds
        if round_number == 0:
            self._last_processed_round = 0
            return Action.D
        if round_number >= max(0, n_rounds - 2):
            self._last_processed_round = round_number
            return Action.D
        last_opp_coops = int(history.opponent_cooperators[-1])
        my_prev_action = bool(history.my_actions[-1])
        total_last = last_opp_coops + (1 if my_prev_action else 0)
        threshold_met = total_last >= m
        if threshold_met:
            self._consecutive_successes += 1
            if self._consecutive_successes >= 2:
                self._permanent_defect = True
        else:
            self._consecutive_successes = 0
            self._permanent_defect = False
        if not threshold_met:
            self._last_processed_round = round_number
            return Action.D
        if last_opp_coops >= m:
            self._last_processed_round = round_number
            return Action.D
        if self._permanent_defect:
            self._last_processed_round = round_number
            return Action.D
        if last_opp_coops == m - 1:
            if my_prev_action and total_last >= m:
                self._last_processed_round = round_number
                return Action.C
            self._last_processed_round = round_number
            return Action.D
        self._last_processed_round = round_number
        return Action.D

class Strategy_INDIVIDUALISTIC_124(BaseStrategy):
    """
    Threshold-chasing strategy with simple stability tracking.

    - Cooperates in the first round only when the threshold is attainable and
      the reward appears worth probing.
    - Thereafter, cooperates only when pivotal for meeting the threshold.
    - Defects whenever the threshold is already safe without self-cooperation.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.n_players = int(game_description.n_players)
        self.n_rounds = int(game_description.n_rounds)
        self.m = int(game_description.m)
        self.k = float(game_description.k)

    def __call__(self, history: PlayerHistory) -> Action:
        round_number = history.round_number
        if round_number == 0:
            if self.m <= self.n_players - 1 and self.k > 1.0:
                return Action.C
            return Action.D
        last_other_cooperators = int(history.opponent_cooperators[-1])
        if last_other_cooperators < 0:
            last_other_cooperators = 0
        total_if_defect = last_other_cooperators
        total_if_cooperate = last_other_cooperators + 1
        threshold_met_if_defect = total_if_defect >= self.m
        threshold_met_if_cooperate = total_if_cooperate >= self.m
        is_final_round = round_number >= self.n_rounds - 1
        if is_final_round:
            if not threshold_met_if_defect and threshold_met_if_cooperate:
                return Action.C
            return Action.D
        if threshold_met_if_defect:
            return Action.D
        if threshold_met_if_cooperate:
            return Action.C
        return Action.D

class Strategy_INDIVIDUALISTIC_125(BaseStrategy):
    """
    Defect by default, and cooperate only after two consecutive
    near-threshold rounds (exactly m-1 cooperating opponents),
    provided the current round is not the final round.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.last = None
        self.near_streak = 0

    def __call__(self, history: PlayerHistory) -> Action:
        gd = self.game_description
        round_number = history.round_number
        if round_number == 0 or round_number >= gd.n_rounds - 1:
            self.last = Action.D
            self.near_streak = 0
            return Action.D
        streak = 0
        idx = round_number - 1
        while idx >= 0 and history.opponent_cooperators[idx] == gd.m - 1:
            streak += 1
            idx -= 1
        if round_number > 0 and history.opponent_cooperators[-1] <= gd.m - 2:
            self.near_streak = 0
        elif round_number > 0 and history.opponent_cooperators[-1] >= gd.m:
            self.near_streak = 0
        else:
            self.near_streak = streak
        if self.near_streak >= 2 and round_number < gd.n_rounds - 1:
            self.last = Action.C
            return Action.C
        self.last = Action.D
        return Action.D

class Strategy_INDIVIDUALISTIC_126(BaseStrategy):
    """
    Start closed, require sustained high cooperation to enter cooperation,
    use hysteresis to remain cooperative, and defect in the final two rounds.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.n_players = game_description.n_players
        self.n_rounds = game_description.n_rounds
        self.m = game_description.m
        self.k = game_description.k
        self.q = max(0, self.m - 1)
        self.H = int(math.ceil((self.n_players - 1) / 2.0))

    def __call__(self, history: PlayerHistory) -> Action:
        t = history.round_number
        if t == 0:
            return Action.D
        if t >= max(0, self.n_rounds - 2):
            return Action.D
        x_prev = int(history.opponent_cooperators[-1]) if len(history.opponent_cooperators) > 0 else 0
        last_action_c = bool(history.my_actions[-1]) if len(history.my_actions) > 0 else False
        low_two_rounds = False
        if len(history.opponent_cooperators) >= 2:
            low_two_rounds = int(history.opponent_cooperators[-1]) < self.q and int(history.opponent_cooperators[-2]) < self.q
        if low_two_rounds and x_prev < self.H:
            return Action.D
        if last_action_c:
            return Action.C if x_prev >= self.H else Action.D
        return Action.C if x_prev >= self.q and x_prev >= self.H else Action.D

class Strategy_INDIVIDUALISTIC_127(BaseStrategy):
    """
    Always defects in every round, regardless of history or observed cooperation.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory) -> Action:
        return Action.D

class Strategy_INDIVIDUALISTIC_128(BaseStrategy):
    """
    Defect initially, then cooperate exactly when the previous round had
    one fewer cooperating opponent than the threshold (s == m - 1).
    Otherwise defect.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number == 0:
            return Action.D
        m = self.game_description.m
        s = int(history.opponent_cooperators[-1])
        if s == m - 1:
            return Action.C
        return Action.D